  });
}

import { UserRole, type AssetModel, type AssetInstance } from "@prisma/client";

type Role = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";

type AssetInstanceWithModel = AssetInstance & { model?: AssetModel | null };

export function sanitizeAssetModel(
  model: AssetModel,
  role: Role,
): Record<string, unknown> {
  const base = model as unknown as Record<string, unknown>;

  if (role === "EMPLOYEE" || role === "MANAGER") {
    const { purchasePrice, supplier, sn, ...rest } = base;
    return rest;
  }

  if (role === "EXECUTIVE") {
    const { supplier, sn, ...rest } = base;
    return rest;
  }

  // IT_ADMIN: full visibility
  return base;
}

export function sanitizeAssetInstance(
  instance: AssetInstanceWithModel,
  role: Role,
): Record<string, unknown> {
  const base = { ...instance } as unknown as Record<string, unknown>;

  if (instance.model) {
    base.model = sanitizeAssetModel(instance.model, role) as Record<
      string,
      unknown
    >;
  }

  if (role === "EMPLOYEE" || role === "MANAGER") {
    const { purchasePrice, supplier, sn, ...rest } = base;
    return rest;
  }

  if (role === "EXECUTIVE") {
    const { supplier, sn, ...rest } = base;
    return rest;
  }

  return base;
}

import type { Prisma } from "@prisma/client";
import { NotificationType } from "@prisma/client";

function ticketTypeName(type: string): string {
  const names: Record<string, string> = {
    APPLY: "申领",
    RETURN: "归还",
    REPAIR: "报修",
    TRANSFER: "调拨",
  };
  return names[type] ?? type;
}

export async function createNotification(
  tx: Prisma.TransactionClient,
  params: {
    userId: string;
    type: NotificationType;
    title: string;
    body: string;
    relatedTicketId?: string;
    relatedAssetId?: string;
  },
): Promise<void> {
  await tx.notification.create({
    data: {
      userId: params.userId,
      type: params.type,
      title: params.title,
      body: params.body,
      relatedTicketId: params.relatedTicketId ?? null,
      relatedAssetId: params.relatedAssetId ?? null,
    },
  });
}

export async function notifyApprovalRequest(
  tx: Prisma.TransactionClient,
  params: {
    managerId: string;
    ticketId: string;
    applicantName: string;
    ticketType: string;
  },
): Promise<void> {
  await createNotification(tx, {
    userId: params.managerId,
    type: "APPROVAL_REQUEST",
    title: "审批请求",
    body: `${params.applicantName} 提交了${ticketTypeName(params.ticketType)}申请，请审批。`,
    relatedTicketId: params.ticketId,
  });
}

export async function notifyApprovalResult(
  tx: Prisma.TransactionClient,
  params: {
    applicantId: string;
    ticketId: string;
    approved: boolean;
    ticketType: string;
  },
): Promise<void> {
  const resultText = params.approved ? "已通过" : "被驳回";
  await createNotification(tx, {
    userId: params.applicantId,
    type: "APPROVAL_RESULT",
    title: "审批结果",
    body: `您的${ticketTypeName(params.ticketType)}申请${resultText}。`,
    relatedTicketId: params.ticketId,
  });
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { createAuditLog, logTicketStatusChange } from "@/lib/audit";
import { notifyApprovalRequest } from "@/lib/notifications";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "EMPLOYEE", "MANAGER");

    const body = await request.json();
    const { modelId, reason, targetDeptId } = body;

    if (!modelId || !reason) {
      return Response.json(
        { error: "modelId and reason are required" },
        { status: 400 },
      );
    }

    const result = await prisma.$transaction(async (tx) => {
      const model = await tx.assetModel.findUnique({ where: { id: modelId } });
      if (!model) {
        throw new WorkflowError("Asset model not found");
      }

      const initialStatus = TicketWorkflow.determineInitialStatus("APPLY", {
        isManager: user.role === "MANAGER",
        purchasePrice: Number(model.purchasePrice),
      });

      const ticket = await tx.ticket.create({
        data: {
          type: "APPLY",
          status: initialStatus,
          applicantId: user.userId,
          targetModelId: modelId,
          reason,
          targetDeptId: targetDeptId ?? null,
        },
      });

      await logTicketStatusChange(tx, {
        ticketId: ticket.id,
        operatorId: user.userId,
        fromStatus: "SUBMITTED",
        toStatus: initialStatus,
        metadata: { modelId, purchasePrice: Number(model.purchasePrice) },
      });

      // Notify department manager if pending manager approval
      if (initialStatus === "PENDING_MANAGER_1") {
        const dept = await tx.department.findUnique({
          where: { id: user.deptId },
          include: { manager: true },
        });
        if (dept?.manager) {
          await notifyApprovalRequest(tx, {
            managerId: dept.manager.id,
            ticketId: ticket.id,
            applicantName: "",
            ticketType: "APPLY",
          });
        }
      }

      return ticket;
    });

    return Response.json(result, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "EMPLOYEE", "MANAGER");

    const body = await request.json();
    const { assetId, reason } = body;

    if (!assetId || !reason) {
      return Response.json(
        { error: "assetId and reason are required" },
        { status: 400 },
      );
    }

    const result = await prisma.$transaction(async (tx) => {
      const asset = await tx.assetInstance.findUnique({
        where: { id: assetId },
      });
      if (!asset) {
        throw new WorkflowError("Asset not found");
      }
      if (asset.holderId !== user.userId) {
        throw new WorkflowError("You are not the holder of this asset");
      }
      if (!AssetStateMachine.canTransition(asset.status, "RETURNING")) {
        throw new TransitionError(
          `Asset cannot be returned from ${asset.status} status`,
        );
      }

      // Check for existing non-terminal return ticket
      const existingReturn = await tx.ticket.findFirst({
        where: {
          type: "RETURN",
          targetAssetId: assetId,
          applicantId: user.userId,
          status: { notIn: ["COMPLETED", "CANCELLED", "REJECTED"] },
        },
      });
      if (existingReturn) {
        throw new WorkflowError("A return request already exists for this asset");
      }

      const initialStatus = TicketWorkflow.determineInitialStatus("RETURN", {
        isManager: user.role === "MANAGER",
      });

      const ticket = await tx.ticket.create({
        data: {
          type: "RETURN",
          status: initialStatus,
          applicantId: user.userId,
          targetAssetId: assetId,
          reason,
        },
      });

      // Asset -> RETURNING
      const transitionResult = await AssetStateMachine.transition(
        tx,
        assetId,
        "RETURNING",
        { operatorId: user.userId },
      );

      await logAssetStatusChange(tx, {
        assetId,
        operatorId: user.userId,
        fromStatus: transitionResult.before.status as string,
        toStatus: "RETURNING",
        metadata: { ticketId: ticket.id },
      });

      await logTicketStatusChange(tx, {
        ticketId: ticket.id,
        operatorId: user.userId,
        fromStatus: "SUBMITTED",
        toStatus: initialStatus,
      });

      return { ticket, asset: transitionResult.after };
    });

    return Response.json(result, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError || e instanceof TransitionError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

