import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";
import { notifyApprovalRequest } from "@/lib/notifications";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "IT_ADMIN");

    const body = await request.json();
    const { assetId, fromHolderId, toHolderId, targetDeptId, reason } = body;

    if (!assetId || !toHolderId || !reason) {
      return Response.json(
        { error: "assetId, toHolderId, and reason are required" },
        { status: 400 },
      );
    }

    const result = await prisma.$transaction(async (tx) => {
      const asset = await tx.assetInstance.findUnique({
        where: { id: assetId },
        include: { model: true },
      });
      if (!asset) {
        throw new WorkflowError("Asset not found");
      }
      if (asset.status !== "IN_USE") {
        throw new TransitionError(
          `Asset must be IN_USE to transfer, current status: ${asset.status}`,
        );
      }

      const initialStatus = TicketWorkflow.determineInitialStatus("TRANSFER", {
        isManager: false,
        hasFromHolder: !!fromHolderId,
      });

      const ticket = await tx.ticket.create({
        data: {
          type: "TRANSFER",
          status: initialStatus,
          applicantId: user.userId,
          targetAssetId: assetId,
          fromHolderId: fromHolderId ?? null,
          toHolderId,
          targetDeptId: targetDeptId ?? null,
          reason,
        },
      });

      // Asset -> TRANSFERRING
      const transitionResult = await AssetStateMachine.transition(
        tx,
        assetId,
        "TRANSFERRING",
        { operatorId: user.userId },
      );

      await logAssetStatusChange(tx, {
        assetId,
        operatorId: user.userId,
        fromStatus: transitionResult.before.status as string,
        toStatus: "TRANSFERRING",
        metadata: { ticketId: ticket.id, toHolderId, fromHolderId },
      });

      await logTicketStatusChange(tx, {
        ticketId: ticket.id,
        operatorId: user.userId,
        fromStatus: "SUBMITTED",
        toStatus: initialStatus,
      });

      // Notify department managers if needed
      if (initialStatus === "PENDING_MANAGER_1" && fromHolderId) {
        const fromHolder = await tx.user.findUnique({
          where: { id: fromHolderId },
        });
        if (fromHolder) {
          const dept = await tx.department.findUnique({
            where: { id: fromHolder.deptId },
            include: { manager: true },
          });
          if (dept?.manager) {
            await notifyApprovalRequest(tx, {
              managerId: dept.manager.id,
              ticketId: ticket.id,
              applicantName: "",
              ticketType: "TRANSFER",
            });
          }
        }
      }

      return { ticket, asset: transitionResult.after };
    });

    return Response.json(result, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError || e instanceof TransitionError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";

export async function GET(request: NextRequest) {
  try {
    const user = await verifyAuth(request);

    const url = request.nextUrl;
    const page = Math.max(1, parseInt(url.searchParams.get("page") ?? "1", 10));
    const pageSize = Math.min(
      100,
      Math.max(1, parseInt(url.searchParams.get("pageSize") ?? "20", 10)),
    );
    const type = url.searchParams.get("type");
    const status = url.searchParams.get("status");

    const where: Record<string, unknown> = {
      applicantId: user.userId,
    };
    if (type) where.type = type;
    if (status) where.status = status;

    const [tickets, total] = await Promise.all([
      prisma.ticket.findMany({
        where: where as any,
        orderBy: { createdAt: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: {
          targetAsset: { include: { model: true } },
          targetModel: true,
        },
      }),
      prisma.ticket.count({ where: where as any }),
    ]);

    return Response.json({
      data: tickets,
      pagination: {
        page,
        pageSize,
        total,
        totalPages: Math.ceil(total / pageSize),
      },
    });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const user = await verifyAuth(request);
    const { id } = await params;

    const ticket = await prisma.ticket.findUnique({
      where: { id },
      include: {
        applicant: { select: { id: true, name: true, email: true, role: true, deptId: true } },
        targetAsset: { include: { model: true } },
        targetModel: true,
        assignedBy: { select: { id: true, name: true } },
        processor: { select: { id: true, name: true } },
        fromHolder: { select: { id: true, name: true } },
        toHolder: { select: { id: true, name: true } },
        targetDept: true,
        deputyApprover: { select: { id: true, name: true } },
        notifications: { orderBy: { createdAt: "desc" }, take: 10 },
      },
    });

    if (!ticket) {
      return Response.json({ error: "Ticket not found" }, { status: 404 });
    }

    const isApplicant = ticket.applicantId === user.userId;
    const isItAdmin = user.role === "IT_ADMIN";

    // MANAGER can see tickets from their department
    const isManager = user.role === "MANAGER";
    let canView = isApplicant || isItAdmin;

    if (isManager && !canView) {
      const dept = await prisma.department.findUnique({
        where: { id: user.deptId },
      });
      if (dept && dept.managerId === user.userId) {
        const applicant = await prisma.user.findUnique({
          where: { id: ticket.applicantId },
          select: { deptId: true },
        });
        if (applicant && applicant.deptId === user.deptId) {
          canView = true;
        }
      }
    }

    if (!canView) {
      return Response.json({ error: "Forbidden" }, { status: 403 });
    }

    return Response.json(ticket);
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { logTicketStatusChange } from "@/lib/audit";
import { notifyApprovalResult, notifyApprovalRequest } from "@/lib/notifications";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "MANAGER", "IT_ADMIN");

    const { id } = await params;
    const body = await request.json();
    const { deputy } = body;

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUnique({
        where: { id },
        include: { applicant: true },
      });
      if (!ticket) {
        throw new WorkflowError("Ticket not found");
      }

      const currentStatus = ticket.status as import("@prisma/client").TicketStatus;

      // Determine who can approve at this stage
      if (currentStatus === "PENDING_MANAGER_1" || currentStatus === "PENDING_MANAGER_2") {
        const isIT = user.role === "IT_ADMIN";
        const isManager = user.role === "MANAGER";

        if (isManager && !isIT) {
          // MANAGER must be in the same department as applicant
          const applicant = await tx.user.findUnique({
            where: { id: ticket.applicantId },
          });
          if (!applicant || applicant.deptId !== user.deptId) {
            throw new WorkflowError("You can only approve tickets for your own department");
          }
        }

        if (isIT && deputy !== true) {
          throw new WorkflowError("IT_ADMIN can only approve as deputy (deputy: true)");
        }
      } else if (currentStatus === "PENDING_IT") {
        if (user.role !== "IT_ADMIN") {
          throw new WorkflowError("Only IT_ADMIN can approve at this stage");
        }
      } else {
        throw new WorkflowError(`Ticket cannot be approved in ${currentStatus} status`);
      }

      const nextStatus = TicketWorkflow.nextOnApprove(
        ticket.type as import("@prisma/client").TicketType,
        currentStatus,
      );
      if (!nextStatus) {
        throw new WorkflowError("No valid approval target for this status");
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: {
          status: nextStatus,
          ...(deputy ? { deputyApproval: true, deputyApproverId: user.userId } : {}),
        },
      });

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: currentStatus,
        toStatus: nextStatus,
        metadata: { deputy: !!deputy },
      });

      // Notify applicant
      await notifyApprovalResult(tx, {
        applicantId: ticket.applicantId,
        ticketId: id,
        approved: true,
        ticketType: ticket.type,
      });

      // If moving to PENDING_IT after manager approval, notify IT (no specific notification needed here)

      // If moving to PENDING_MANAGER_2 (transfer), notify the next manager
      if (nextStatus === "PENDING_MANAGER_2") {
        const dept = await tx.department.findUnique({
          where: { id: user.deptId },
          include: { manager: true },
        });
        if (dept?.manager) {
          await notifyApprovalRequest(tx, {
            managerId: dept.manager.id,
            ticketId: id,
            applicantName: "",
            ticketType: ticket.type,
          });
        }
      }

      return updated;
    });

    return Response.json(result);
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";
import { notifyApprovalResult } from "@/lib/notifications";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "MANAGER", "IT_ADMIN");

    const { id } = await params;
    const body = await request.json();
    const { rejectReason } = body;

    if (!rejectReason) {
      return Response.json({ error: "rejectReason is required" }, { status: 400 });
    }

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUnique({
        where: { id },
        include: { applicant: true, targetAsset: true },
      });
      if (!ticket) {
        throw new WorkflowError("Ticket not found");
      }

      const currentStatus = ticket.status as import("@prisma/client").TicketStatus;

      // Same role checks as approve
      if (currentStatus === "PENDING_MANAGER_1" || currentStatus === "PENDING_MANAGER_2") {
        if (user.role === "MANAGER") {
          const applicant = await tx.user.findUnique({
            where: { id: ticket.applicantId },
          });
          if (!applicant || applicant.deptId !== user.deptId) {
            throw new WorkflowError("You can only reject tickets for your own department");
          }
        }
      } else if (currentStatus === "PENDING_IT") {
        if (user.role !== "IT_ADMIN") {
          throw new WorkflowError("Only IT_ADMIN can reject at this stage");
        }
      } else if (currentStatus !== "APPROVED") {
        throw new WorkflowError(`Ticket cannot be rejected in ${currentStatus} status`);
      }

      // Recover asset status if applicable (RETURN -> AVAILABLE, REPAIR -> IN_USE)
      const assetChanges: Record<string, unknown>[] = [];
      if (ticket.targetAsset) {
        const assetType = ticket.type as import("@prisma/client").TicketType;
        if (assetType === "RETURN" && ticket.targetAsset.status === "RETURNING") {
          const transition = await AssetStateMachine.transition(
            tx,
            ticket.targetAsset.id,
            "AVAILABLE",
            { operatorId: user.userId },
          );
          assetChanges.push(transition.after);
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "RETURNING",
            toStatus: "AVAILABLE",
            metadata: { ticketId: id, reason: "rejected" },
          });
        } else if (assetType === "REPAIR" && ticket.targetAsset.status === "REPAIRING") {
          const transition = await AssetStateMachine.transition(
            tx,
            ticket.targetAsset.id,
            "IN_USE",
            { operatorId: user.userId },
          );
          assetChanges.push(transition.after);
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "REPAIRING",
            toStatus: "IN_USE",
            metadata: { ticketId: id, reason: "rejected" },
          });
        }
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: {
          status: "REJECTED",
          rejectReason,
        },
      });

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: currentStatus,
        toStatus: "REJECTED",
        metadata: { rejectReason },
      });

      await notifyApprovalResult(tx, {
        applicantId: ticket.applicantId,
        ticketId: id,
        approved: false,
        ticketType: ticket.type,
      });

      return { ticket: updated, assetChanges };
    });

    return Response.json(result);
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError || e instanceof TransitionError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
import { WorkflowError } from "@/lib/ticket-workflow";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const user = await verifyAuth(request);

    const { id } = await params;

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUnique({
        where: { id },
        include: { targetAsset: true },
      });
      if (!ticket) {
        throw new WorkflowError("Ticket not found");
      }

      const currentStatus = ticket.status as import("@prisma/client").TicketStatus;

      // Only applicant or IT_ADMIN can cancel
      if (ticket.applicantId !== user.userId && user.role !== "IT_ADMIN") {
        throw new WorkflowError("Only the applicant or IT admin can cancel this ticket");
      }

      // Cannot cancel terminal tickets
      if (["COMPLETED", "REJECTED", "CANCELLED"].includes(currentStatus)) {
        throw new WorkflowError(
          `Cannot cancel a ticket in ${currentStatus} status`,
        );
      }

      // Recover asset status if applicable
      const assetChanges: Record<string, unknown>[] = [];
      if (ticket.targetAsset) {
        const assetStatus = ticket.targetAsset.status;
        const ticketType = ticket.type as import("@prisma/client").TicketType;

        // Determine recovery status based on current asset status
        if (
          (ticketType === "RETURN" && assetStatus === "RETURNING") ||
          (ticketType === "REPAIR" && assetStatus === "REPAIRING")
        ) {
          let recoveryStatus: import("@prisma/client").AssetInstanceStatus = "AVAILABLE";
          if (ticket.fromHolderId) {
            recoveryStatus = "IN_USE";
          }
          // For repair, recover to IN_USE if the asset was previously held
          if (ticketType === "REPAIR" && ticket.fromHolderId) {
            recoveryStatus = "IN_USE";
          }
          // For return, recover to IN_USE if held
          if (ticketType === "RETURN" && ticket.fromHolderId) {
            recoveryStatus = "IN_USE";
          }

          const transition = await AssetStateMachine.transition(
            tx,
            ticket.targetAsset.id,
            recoveryStatus,
            { operatorId: user.userId },
          );

          // Set holder back if recovering to IN_USE
          if (recoveryStatus === "IN_USE" && ticket.fromHolderId) {
            await tx.assetInstance.update({
              where: { id: ticket.targetAsset.id },
              data: { holderId: ticket.fromHolderId },
            });
          }

          assetChanges.push(transition.after);
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: assetStatus,
            toStatus: recoveryStatus,
            metadata: { ticketId: id, reason: "cancelled" },
          });
        } else if (ticketType === "TRANSFER" && assetStatus === "TRANSFERRING") {
          const transition = await AssetStateMachine.transition(
            tx,
            ticket.targetAsset.id,
            "IN_USE",
            { operatorId: user.userId },
          );
          assetChanges.push(transition.after);
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "TRANSFERRING",
            toStatus: "IN_USE",
            metadata: { ticketId: id, reason: "cancelled" },
          });
        }
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: { status: "CANCELLED" },
      });

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: currentStatus,
        toStatus: "CANCELLED",
      });

      return { ticket: updated, assetChanges };
    });

    return Response.json(result);
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError || e instanceof TransitionError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";
import { WorkflowError } from "@/lib/ticket-workflow";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "IT_ADMIN");

    const { id } = await params;
    const body = await request.json();
    const { assetId } = body;

    if (!assetId) {
      return Response.json({ error: "assetId is required" }, { status: 400 });
    }

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUnique({
        where: { id },
        include: { applicant: true },
      });
      if (!ticket) {
        throw new WorkflowError("Ticket not found");
      }

      const currentStatus = ticket.status as import("@prisma/client").TicketStatus;
      if (currentStatus !== "APPROVED") {
        throw new WorkflowError(
          `Ticket must be APPROVED before assigning, current: ${currentStatus}`,
        );
      }

      // Assign the specified asset to the ticket
      const transition = await AssetStateMachine.transition(
        tx,
        assetId,
        "ASSIGNED",
        { operatorId: user.userId },
      );

      await logAssetStatusChange(tx, {
        assetId,
        operatorId: user.userId,
        fromStatus: transition.before.status as string,
        toStatus: "ASSIGNED",
        metadata: { ticketId: id, applicantId: ticket.applicantId },
      });

      const updated = await tx.ticket.update({
        where: { id },
        data: {
          status: "IN_PROGRESS",
          targetAssetId: assetId,
          assignedById: user.userId,
        },
      });

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: currentStatus,
        toStatus: "IN_PROGRESS",
        metadata: { assignedAssetId: assetId },
      });

      return { ticket: updated, asset: transition.after };
    });

    return Response.json(result);
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError || e instanceof TransitionError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

