          targetAsset: { include: { model: true } },
          targetModel: true,
        },
      }),
      prisma.ticket.count({ where: where as any }),
    ]);

    return Response.json({
      data: tickets,
      pagination: {
        page,
        pageSize,
        total,
        totalPages: Math.ceil(total / pageSize),
      },
    });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError, requireOneOf } from "@/lib/auth";

export async function GET(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "MANAGER", "IT_ADMIN");

    const url = request.nextUrl;
    const page = Math.max(1, parseInt(url.searchParams.get("page") ?? "1", 10));
    const pageSize = Math.min(
      100,
      Math.max(1, parseInt(url.searchParams.get("pageSize") ?? "20", 10)),
    );

    // Approvals history: tickets that have been processed
    // For MANAGER: tickets from their department that are in a finished state
    // For IT_ADMIN: tickets they processed
    let where: Record<string, unknown>;

    if (user.role === "IT_ADMIN") {
      where = {
        status: { in: ["APPROVED", "REJECTED", "COMPLETED", "CANCELLED"] },
        OR: [
          { assignedById: user.userId },
          { processorId: user.userId },
        ],
      };
    } else {
      // MANAGER: see tickets from their department
      where = {
        status: { in: ["APPROVED", "REJECTED", "COMPLETED", "CANCELLED"] },
        applicant: { deptId: user.deptId },
      };
    }

    const [tickets, total] = await Promise.all([
      prisma.ticket.findMany({
        where: where as any,
        orderBy: { updatedAt: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: {
          applicant: { select: { id: true, name: true, email: true, deptId: true } },
          targetAsset: { include: { model: true } },
          targetModel: true,
          assignedBy: { select: { id: true, name: true } },
          processor: { select: { id: true, name: true } },
        },
      }),
      prisma.ticket.count({ where: where as any }),
    ]);

    return Response.json({
      data: tickets,
      pagination: {
        page,
        pageSize,
        total,
        totalPages: Math.ceil(total / pageSize),
      },
    });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { sanitizeAssetInstance } from "@/lib/dto";

export async function GET(request: NextRequest) {
  try {
    const user = await verifyAuth(request);

    const url = request.nextUrl;
    const page = Math.max(1, parseInt(url.searchParams.get("page") ?? "1", 10));
    const pageSize = Math.min(
      100,
      Math.max(1, parseInt(url.searchParams.get("pageSize") ?? "20", 10)),
    );

    const where = { holderId: user.userId };

    const [assets, total] = await Promise.all([
      prisma.assetInstance.findMany({
        where,
        orderBy: { updatedAt: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: { model: true },
      }),
      prisma.assetInstance.count({ where }),
    ]);

